1.快速排序标准版本：
function quickSort(list, start, end) &#123;    if (end &lt;= start) &#123;        return;    &#125;    let left = start;    let right = end;    while (left &lt; right) &#123;        while (list[right] &gt; list[start]) &#123;            right--;        &#125;        while (list[left] &lt;= list[start]) &#123;            left++;        &#125;        if (left &lt; right) &#123;            let temp = list[left];            list[left] = list[right];            list[right] = temp;        &#125;    &#125;    let temp = list[right];    list[right] = list[start];    list[start] = temp;    quickSort(list, start, right - 1);    quickSort(list, right + 1, end);&#125;

另一种实现方式：
function quickSort(list) &#123;    if (list.length &lt;= 1) &#123;        return list;    &#125;    let left = [];    let right = [];    for (let i = 1; i &lt; list.length; ++i) &#123;        if (list[i] &lt;= list[0]) &#123;            left.push(list[i]);        &#125; else &#123;            right.push(list[i]);        &#125;    &#125;    return quickSort(left).concat(list[0], quickSort(right));&#125;// 也可以用ES6数组的filter方法缩写上述代码function quickSort(list) &#123;    if (list.length &lt;= 1) &#123;        return list;    &#125;    let left = list.filter((x, i) =&gt; x &lt;= list[0] &amp;&amp; i != 0);    let right = list.filter((x) =&gt; x &gt; list[0]);    return quickSort(left).concat(list[0], quickSort(right));&#125;



2.防抖在规定时间后执行函数，如果函数在规定时间内再次被触发，将重新计时。
function debounce(func, gapTime = 1500) &#123;    let timer = null;    return function() &#123;        if (timer !== null) &#123;            clearTimeout(timer);        &#125;        timer = setTimeout(() =&gt; &#123;            func.apply(this, arguments);        &#125;, gapTime)    &#125;&#125;



3.节流规定时间内只执行一次函数。
function throttle(func, gapTime = 1500) &#123;    let lastTime = null    return function() &#123;        let nowTime = Date.now()        if (nowTime - lastTime &gt; gapTime || !lastTime) &#123;            func.apply(this, arguments)            lastTime = nowTime        &#125;    &#125;&#125;

1.JSON转换这是最简单的一种方式：
JSON.parse(JSON.stringify(对象));

但这种方式有很大缺陷，由于它是依赖于JSON，因此它不支持JSON不支持的其他格式，通过JSON的官网可知，JSON只支持Object、Array、String、Number、Boolean、Null这几种数据类型，其他的比如Function、Undefined、Date、RegExp等数据类型都不支持。对于它不支持的数据都会直接忽略该属性。
另外，如果对象存在循环引用的情况，会导致栈溢出。


2.递归函数通过JSON转换有那么多问题，那我们就需要自己手写一个深拷贝方法，最常用的就是通过递归实现。
(1) 基础版本function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = &#123;&#125;;        for (const key in target) &#123;            cloneTarget[key] = clone(target[key]);        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;;

这种方式只能拷贝最简单的对象，还没有考虑其他引用类型：如数组、函数等。
(2) 拷贝数组function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            // 如果是数组            cloneTarget = [];        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        for (const key in target) &#123;            cloneTarget[key] = clone(target[key]);        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;

(3) 拷贝函数对于函数的拷贝其实是有争议的，我认为函数不应该有深拷贝，因为对于函数，绝大多数情况都是用来调用执行，很少用来操作函数对象，所以对于函数的拷贝，我认为只需要拷贝引用即可。
function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            cloneTarget = [];        &#125; else if (target instanceof Function) &#123;            // 如果是函数            cloneTarget = target;        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        for (const key in target) &#123;            cloneTarget[key] = clone(target[key]);        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;

(4) 拷贝正则表达式const re = /test/g;

一个正则表达式由模式和修饰符组成，/test/为正则模式，g为修饰符。拷贝一个正则表达式，只需获取这两部分即可。通过正则对象的source属性可以获取正则规则，flags属性可以获取修饰符。
function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            cloneTarget = [];        &#125; else if (target instanceof Function) &#123;            cloneTarget = target;        &#125; else if (target instanceof RegExp)&#123;            // 如果是正则表达式            cloneTarget = new RegExp(target.source, target.flags);        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        for (const key in target) &#123;            cloneTarget[key] = clone(target[key]);        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;

(5) 拷贝日期function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            cloneTarget = [];        &#125; else if (target instanceof Function) &#123;            cloneTarget = target;        &#125; else if (target instanceof RegExp) &#123;            cloneTarget = new RegExp(target.source, target.flags);        &#125; else if (target instanceof Date) &#123;            // 如果是日期            cloneTarget = new Date(target);        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        for (const key in target) &#123;            cloneTarget[key] = clone(target[key]);        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;


到目前为止，我们已经写出了一个可以使用的深拷贝函数，但是这个函数仍存在很多可以优化的地方。


3.进一步优化(1) 忽略原型上的属性我们在遍历对象属性的时候，使用的是for in，for in会遍历包括原型上的所有可迭代属性，但是事实上我们不应该这么做。所以我们需要通过hasOwnProperty筛选出自身的属性。
function clone(target) &#123;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            cloneTarget = [];        &#125; else if (target instanceof Function) &#123;            cloneTarget = target;        &#125; else if (target instanceof RegExp) &#123;            cloneTarget = new RegExp(target.source, target.flags);        &#125; else if (target instanceof Date) &#123;            cloneTarget = new Date(target);        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        for (const key in target) &#123;            // 筛选自身属性            if (target.hasOwnProperty(key)) &#123;                cloneTarget[key] = clone(target[key]);            &#125;        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;



(2) 循环引用问题解决循环引用问题的关键点在于判断一个对象是否已经被拷贝过，如果拷贝过直接返回拷贝后的对象。所以我们需要一个东西帮我们记录，最好的方式就是map。
let cache = new Map();function clone(target) &#123;    // 如果已经拷贝过，直接返回拷贝后的对象    if (cache.get(target)) &#123;        return cache.get(target);    &#125;    if (target instanceof Object) &#123;        let cloneTarget = null;        if (target instanceof Array) &#123;            cloneTarget = [];        &#125; else if (target instanceof Function) &#123;            cloneTarget = target;        &#125; else if (target instanceof RegExp) &#123;            cloneTarget = new RegExp(target.source, target.flags);        &#125; else if (target instanceof Date) &#123;            cloneTarget = new Date(target);        &#125; else &#123;            cloneTarget = &#123;&#125;;        &#125;        // 记录拷贝对象        cache.set(target, cloneTarget);        for (const key in target) &#123;            if (target.hasOwnProperty(key)) &#123;                cloneTarget[key] = clone(target[key]);            &#125;        &#125;        return cloneTarget;    &#125; else &#123;        return target;    &#125;&#125;





